const matchedCurrentOption = chooseOptionFromMessage(currentVariationOptions, currentMessage);
const matchedOption = matchedCurrentOption || matchedPreviousOption;
const currentOrderSelectionSignal = Boolean(
  currentQuantity !== null ||
  /@/.test(currentMessage) ||
  currentMeasureTokens.length > 0 ||
  confirmRegex.test(currentMessage) ||
  /\b(option|opcao|same like before|igual(?: ao?| a)? ?antes|send me link|payment link|link)\b/i.test(normalizedCurrentMessage)
);
const userSeemsToBeChangingProduct = Boolean(
  previousProduct &&
  currentProductTokens.length > 0 &&
  !currentOrderSelectionSignal &&
  bestProduct &&
  String(bestProduct.product_id || '') !== String(previousProduct.product_id || '')
);
const shouldKeepPreviousProduct = Boolean(
  previousProduct &&
  orderConversationRequested &&
  !explicitNewOrderRequest &&
  !userSeemsToBeChangingProduct
);

let selectedProduct = null;
if (matchedOption) {
  const exactRow = candidateRows.find((row) => String(row.variation_id || '') === String(matchedOption.variation_id || ''))
    || rows.find((row) => String(row.variation_id || '') === String(matchedOption.variation_id || ''));
  selectedProduct = buildProductOption(exactRow || matchedOption);
} else if (shouldKeepPreviousProduct) {
  selectedProduct = previousProduct;
} else if (bestProduct && currentVariationOptions.length <= 1) {
  selectedProduct = buildProductOption(bestProduct);
}

let variationOptions = [];
if (!selectedProduct) {
  variationOptions = currentVariationOptions.length > 0 ? currentVariationOptions : previousVariationOptions;
}
if (!orderConversationRequested) {
  selectedProduct = null;
  variationOptions = [];
}

const now = Date.now();

const missingFields = [];
if (!selectedProduct && variationOptions.length > 0) missingFields.push('variation');
else if (!selectedProduct) missingFields.push('product');
if (!Number.isInteger(quantity) || quantity <= 0) missingFields.push('quantity');
if (!billingEmail) missingFields.push('email');
if (!billingCpf) missingFields.push('cpf');
if (!billingAddress1) missingFields.push('address_1');
if (!billingNumber) missingFields.push('number');
if (!billingCity) missingFields.push('city');
if (!billingState) missingFields.push('state');
if (!billingPostcode) missingFields.push('postcode');

const unitPrice = selectedProduct ? parseNumber(selectedProduct.effective_price ?? selectedProduct.price) : null;
const subtotal = selectedProduct && unitPrice !== null && Number.isInteger(quantity) && quantity > 0
  ? Number((unitPrice * quantity).toFixed(2))
  : null;
const shippingCost = selectedProduct && isTruthyTag(selectedProduct.free_shipping_tag) ? 0 : null;
const totalAmount = subtotal !== null ? Number((subtotal + (shippingCost ?? 0)).toFixed(2)) : null;
const orderReview = selectedProduct ? {
  items: [{
    product_id: selectedProduct.product_id || '',
    variation_id: selectedProduct.variation_id || '',
    display_name: buildOrderDisplayName(selectedProduct),
    title: selectedProduct.title || '',
    variation_label: selectedProduct.variation_label || '',
    quantity,
    unit_price: unitPrice,
    line_total: subtotal,
    product_url: selectedProduct.product_url || ''
  }],
  subtotal,
  shipping_cost: shippingCost,
  shipping_cost_known: shippingCost !== null,
  total_amount: totalAmount,
  total_amount_is_estimate: shippingCost === null,
  billing_email: billingEmail,
  billing_cpf: billingCpf,
  delivery_address: {
    address_1: billingAddress1,
    number: billingNumber,
    neighborhood: billingNeighborhood,
    city: billingCity,
    state: billingState,
    postcode: billingPostcode,
    country: 'BR'
  }
} : null;

let orderCreationStatus = 'not_requested';
const explicitConfirmationToCreate = confirmRegex.test(currentMessage)
  && (previousOrderCreationStatus === 'awaiting_confirmation' || previousOrderCreationStatus === 'create_failed' || previousOrderCreationStatus === 'ready_to_create')
  && previousMissingFields.length === 0
  && Boolean(previousProduct || selectedProduct);
if (orderActionRequested) {
  if (!supportContext.config.orderCreationEnabled) orderCreationStatus = 'disabled';
  else if (missingFields.length > 0) orderCreationStatus = 'needs_info';
  else if (explicitConfirmationToCreate) orderCreationStatus = 'ready_to_create';
  else orderCreationStatus = 'awaiting_confirmation';
}

let orderPayload = null;
if (orderCreationStatus === 'ready_to_create' && selectedProduct) {
  const lineItem = { product_id: Number.parseInt(selectedProduct.product_id, 10), quantity };
  const parsedVariationId = Number.parseInt(selectedProduct.variation_id || '0', 10);
  if (Number.isInteger(parsedVariationId) && parsedVariationId > 0) lineItem.variation_id = parsedVariationId;
  orderPayload = {
    status: 'pending',
    set_paid: false,
    billing: {
      first_name: supportContext.contactName || 'WhatsApp Customer',
      email: billingEmail,
      phone: supportContext.contactPhone || '',
      address_1: billingAddress1,
      address_2: '',
      neighborhood: billingNeighborhood,
      bairro: billingNeighborhood,
      city: billingCity,
      state: billingState,
      postcode: billingPostcode,
      country: 'BR'
    },
    shipping: {
      first_name: supportContext.contactName || 'WhatsApp Customer',
      address_1: billingAddress1,
      address_2: '',
      city: billingCity,
      state: billingState,
      postcode: billingPostcode,
      country: 'BR'
    },
    line_items: [lineItem],
    customer_note: `Created from Chatwoot conversation \${supportContext.conversationId}.`,
    meta_data: [
      { key: '_chatwoot_conversation_id', value: String(supportContext.conversationId || '') },
      { key: '_chatwoot_contact_phone', value: String(supportContext.contactPhone || '') },
      { key: '_billing_cpf', value: billingCpf },
      { key: '_billing_address_1', value: billingAddress1 },
      { key: '_billing_number', value: billingNumber },
      { key: '_billing_neighborhood', value: billingNeighborhood },
      { key: '_billing_bairro', value: billingNeighborhood },
      { key: '_billing_city', value: billingCity },
      { key: '_billing_state', value: billingState },
      { key: '_billing_postcode', value: billingPostcode },
      { key: '_shipping_number', value: billingNumber },
      { key: '_shipping_neighborhood', value: billingNeighborhood },
      { key: '_shipping_bairro', value: billingNeighborhood }
    ]
  };
}
if (conversationKey && staticStore) {
  if (billingEmail || billingCpf || billingAddress1 || billingNumber || billingNeighborhood || billingCity || billingState || billingPostcode) {
    conversationMemory[conversationKey] = {
      ...(conversationMemory[conversationKey] || {}),
      billingEmail,
      billingCpf,
      billingAddress1,
      billingNumber,
      billingNeighborhood,
      billingCity,
      billingState,
      billingPostcode,
      updatedAt: now
    };
  }

  const currentProfileKeys = [...new Set([
    ...profileKeyCandidates,
    normalizeProfileKey('phone', supportContext.contactPhone),
    normalizeProfileKey('email', billingEmail)
  ].filter(Boolean))];

  if (currentProfileKeys.length > 0) {
    const baseProfile = currentProfileKeys
      .map((key) => customerProfiles[key])
      .find((entry) => entry && typeof entry === 'object') || rememberedProfile || {};

    const priorViewedProducts = Array.isArray(baseProfile.lastViewedProducts) ? baseProfile.lastViewedProducts : [];
    const nextViewedProducts = [...priorViewedProducts];
    if (selectedProduct?.title) {
      nextViewedProducts.push({
        product_id: selectedProduct.product_id || '',
        variation_id: selectedProduct.variation_id || '',
        title: selectedProduct.title || '',
        product_url: selectedProduct.product_url || '',
        updatedAt: now
      });
    }

    const dedupedViewedProducts = [];
    const seenViewedKeys = new Set();
    for (const entry of nextViewedProducts.slice(-12).reverse()) {
      const key = `${entry.product_id || ''}:${entry.variation_id || ''}:${entry.title || ''}`;
      if (!key.trim() || seenViewedKeys.has(key)) continue;
      seenViewedKeys.add(key);
      dedupedViewedProducts.unshift(entry);
    }

    const nextProfile = {
      ...baseProfile,
      contactName: supportContext.contactName || baseProfile.contactName || '',
      phoneNumber: supportContext.contactPhone || baseProfile.phoneNumber || '',
      billingEmail: billingEmail || baseProfile.billingEmail || '',
      billingCpf: billingCpf || baseProfile.billingCpf || '',
      billingAddress1: billingAddress1 || baseProfile.billingAddress1 || '',
      billingNumber: billingNumber || baseProfile.billingNumber || '',
      billingNeighborhood: billingNeighborhood || baseProfile.billingNeighborhood || '',
      billingCity: billingCity || baseProfile.billingCity || '',
      billingState: billingState || baseProfile.billingState || '',
      billingPostcode: billingPostcode || baseProfile.billingPostcode || '',
      preferredLanguage: supportContext.languageHint || baseProfile.preferredLanguage || '',
      interestTags: [...new Set([...(Array.isArray(baseProfile.interestTags) ? baseProfile.interestTags : []), ...rememberedInterestTags, ...((Array.isArray(supportContext.categoryIntentTags) ? supportContext.categoryIntentTags : []))])].filter(Boolean).slice(-12),
      recentSearchTerms: [...new Set([...(Array.isArray(baseProfile.recentSearchTerms) ? baseProfile.recentSearchTerms : []), supportContext.productSearchTerm].filter(Boolean))].slice(-12),
      recentSemanticTokens: [...new Set([...(Array.isArray(baseProfile.recentSemanticTokens) ? baseProfile.recentSemanticTokens : []), ...((Array.isArray(supportContext.semanticSearchTokens) ? supportContext.semanticSearchTokens : []))])].filter(Boolean).slice(-20),
      lastViewedProducts: dedupedViewedProducts,
      lastOrderDraftProduct: selectedProduct || baseProfile.lastOrderDraftProduct || null,
      updatedAt: now
    };

    for (const key of currentProfileKeys) {
      customerProfiles[key] = nextProfile;
    }
  }

  if (orderConversationRequested || selectedProduct || billingEmail || billingCpf || billingAddress1 || billingNumber || billingNeighborhood || billingCity || billingState || billingPostcode || hasExplicitQuantity || variationOptions.length > 0) {
    orderDrafts[conversationKey] = {
      orderConversationRequested,
      orderActionRequested,
      orderCreationStatus,
      missingFields,
      billingEmail,
      billingCpf,
      billingAddress1,
      billingNumber,
      billingNeighborhood,
      billingCity,
      billingState,
      billingPostcode,
      quantity,
      product: selectedProduct || (!explicitNewOrderRequest ? previousProduct : null) || null,
      variationOptions: variationOptions.length > 0 ? variationOptions : (!explicitNewOrderRequest ? previousVariationOptions : []),
      orderReview,
      updatedAt: now
    };
  } else {
    delete orderDrafts[conversationKey];
  }
}
return {
  conversationId: supportContext.conversationId,
  orderConversationRequested,
  orderActionRequested,
  orderCreationStatus,
  missingFields,
  billingEmail,
  billingCpf,
  billingAddress1,
  billingNumber,
  billingNeighborhood,
  billingCity,
  billingState,
  billingPostcode,
  quantity,
  product: selectedProduct,
  variationOptions,
  orderReview,
  orderPayload
};

const orderDraft = $('Prepare Woo Order Draft3').first().json ?? {};
let customerLookupResponse = null;
try { customerLookupResponse = $('Woo Customer Lookup3').first().json ?? null; } catch (error) { customerLookupResponse = null; }

const cloneValue = (value) => {
  if (value === null || value === undefined) return value;
  return JSON.parse(JSON.stringify(value));
};
const toArray = (value) => Array.isArray(value) ? value : [];
const normalizeEmail = (value) => String(value || '').trim().toLowerCase();

const customers = toArray(customerLookupResponse?.body);
const targetEmail = normalizeEmail(orderDraft.billingEmail);
const matchedCustomer = customers.find((customer) => normalizeEmail(customer?.email) === targetEmail) || customers[0] || null;

const orderPayload = cloneValue(orderDraft.orderPayload);
if (orderPayload && matchedCustomer?.id) {
  const parsedCustomerId = Number.parseInt(String(matchedCustomer.id), 10);
  orderPayload.customer_id = Number.isInteger(parsedCustomerId) ? parsedCustomerId : matchedCustomer.id;

  const customerBilling = matchedCustomer.billing && typeof matchedCustomer.billing === 'object' ? matchedCustomer.billing : {};
  const existingBilling = orderPayload.billing && typeof orderPayload.billing === 'object' ? orderPayload.billing : {};
  orderPayload.billing = {
    ...customerBilling,
    ...existingBilling,
    email: orderDraft.billingEmail || existingBilling.email || customerBilling.email || matchedCustomer.email || '',
    phone: existingBilling.phone || customerBilling.phone || '',
    first_name: existingBilling.first_name || customerBilling.first_name || matchedCustomer.first_name || '',
    last_name: existingBilling.last_name || customerBilling.last_name || matchedCustomer.last_name || '',
    address_2: ''
  };
}

return {
  ...orderDraft,
  registeredCustomer: matchedCustomer ? {
    id: matchedCustomer.id,
    email: matchedCustomer.email || '',
    first_name: matchedCustomer.first_name || '',
    last_name: matchedCustomer.last_name || ''
  } : null,
  orderPayload
};

const agentOutput = $input.first().json ?? {};
const content = String(
  agentOutput.output ??
  agentOutput.text ??
  agentOutput.response ??
  agentOutput.answer ??
  ''
).trim();

return [{
  json: {
    statusCode: 200,
    body: {
      choices: [
        {
          message: {
            content
          }
        }
      ]
    }
  }
}];
